import json

with open('C:/books/books.json', encoding='utf-8') as f:
    books = json.load(f)

bible_thoughts = [
  {"title":"В начале было Слово — творение как акт смысла","example":"Библия открывается фразой: «В начале сотворил Бог небо и землю». Это не просто космология — это философская декларация. Мир существует не случайно и не сам по себе: за ним стоит намерение, замысел, смысл. В отличие от других древних мифологий, где мир рождался из хаоса или борьбы богов, в Библии творение — это акт свободного волеизъявления. Бог творит словом, а не трудом. Именно эта идея — что за миром стоит разум и порядок — легла в основу западной науки. Галилей, Ньютон, Кеплер были верующими людьми и искали законы природы именно потому, что верили: мир устроен разумно и познаваем. Без этой предпосылки не было бы научной революции."},
  {"title":"Грехопадение — цена свободы выбора","example":"Адам и Ева жили в раю без страданий, без труда, без смерти. У них было всё — кроме одного: права есть плоды с дерева познания добра и зла. Они нарушили запрет. Богословы спорили об этом тысячи лет: зачем Бог вообще создал это дерево? Ответ, который даёт христианская традиция: Бог мог создать существ без свободы воли — послушных, счастливых, безгрешных. Но это были бы не люди, а живые механизмы. Свобода выбора — это то, что делает человека человеком. А свобода выбора неизбежно включает возможность ошибки. Зло и страдание в мире — не конструктивный дефект, а цена подлинной свободы. Эта идея лежит в основе западной концепции моральной ответственности: человек не жертва обстоятельств, а существо, способное выбирать и отвечать за выбор."},
  {"title":"Десять заповедей — первый универсальный кодекс морали","example":"Около 1300 года до нашей эры Моисей спустился с горы Синай с двумя каменными скрижалями. На них было написано десять заповедей. До этого мораль в большинстве культур была относительной: что разрешено царю, запрещено рабу; что допустимо в своём племени, неприменимо к чужакам. Заповеди провозгласили иное: не убивай, не кради, не лжесвидетельствуй — для всех, без исключений. Это была революция. Единый моральный стандарт, не зависящий от статуса, богатства или происхождения. Римское право, европейские правовые системы, Декларация прав человека — всё это прямые потомки синайского законодательства. Даже в современных атеистических государствах уголовный кодекс строится на тех же принципах: не убивай, не кради, не лги. Три тысячи лет — а фундамент не изменился."},
  {"title":"Золотое правило — универсальный алгоритм этики","example":"«Итак, во всём, как хотите, чтобы с вами поступали люди, так поступайте и вы с ними» — Иисус, Нагорная проповедь. Это называют Золотым правилом, и оно появляется в той или иной форме в каждой мировой религии и этической системе: у Конфуция, в буддизме, в исламе, у Канта. Но именно христианство сделало его центральной нормой. Почему это правило так универсально? Потому что оно решает проблему эгоизма без внешнего принуждения. Перед любым решением достаточно задать один вопрос: хотел бы я, чтобы так поступили со мной? Современная психология называет эту способность эмпатией и считает её фундаментом нравственного развития. Дети, которых учат этому правилу, вырастают с более развитым социальным интеллектом. Нейронауки подтверждают: эмпатия — это не слабость, это один из самых сложных когнитивных навыков человека."},
  {"title":"Нагорная проповедь — этика, перевернувшая мир","example":"Нагорная проповедь — возможно, самый влиятельный текст в истории человечества. Иисус поднялся на гору и сказал: блаженны кроткие, блаженны миротворцы, возлюбите врагов ваших, молитесь за гонящих вас. Для слушателей это звучало как безумие. В мире, где уважали силу, власть и месть, Иисус предложил радикально иную логику: настоящая сила — в смирении, настоящая победа — в прощении. Прошло почти две тысячи лет. Махатма Ганди изучал Нагорную проповедь и построил на её принципах стратегию ненасильственного сопротивления, которая освободила Индию от британского колониализма. Мартин Лютер Кинг цитировал её на каждом митинге и изменил расовую политику США без единого выстрела. Нельсон Мандела 27 лет провёл в тюрьме и вышел без ненависти. Эти слова изменили больше политических режимов, чем любая армия в истории."},
  {"title":"Притча о блудном сыне — самая точная история о прощении","example":"Младший сын приходит к отцу и требует свою долю наследства досрочно — что по меркам того времени равнозначно пожеланию отцу смерти. Отец молча отдаёт. Сын уходит, проматывает всё, оказывается в нищете, пасёт свиней и завидует их корму. Наконец решает вернуться — не как сын, а как наёмный слуга. Но ещё пока он далеко, отец видит его и бежит навстречу. Не ждёт у порога с упрёками. Бежит. Устраивает пир. Старший сын, который всё время был рядом и работал, возмущён: это несправедливо! Отец отвечает: «Он был мёртв и ожил, пропадал и нашёлся». Психолог Карл Юнг считал эту притчу архетипической моделью возвращения к себе после периода потерь и иллюзий. Психотерапевты используют её как метафору прощения без условий. За две тысячи лет эта история не потеряла ни грамма точности — потому что говорит о самом человеческом: о стыде, гордости, потере и принятии."},
  {"title":"Воскресение — центральное событие христианства","example":"Апостол Павел написал прямо и жёстко: «Если Христос не воскрес, то вера ваша тщетна». Воскресение — не периферийная деталь христианства, а его смысловой центр. Для греко-римского мира это была возмутительная идея. Греки верили, что тело — тюрьма для души, и смерть — освобождение. Евреи ждали воскресения всех в конце времён, но не одного человека здесь и сейчас. Христиане заявили о принципиально новом: смерть побеждена уже сейчас, в истории, в конкретном человеке. Это перевернуло отношение к смерти, страданию и мученичеству. Первые христиане шли на смерть спокойно — не из фанатизма, а из убеждения, что смерть не финал. Именно эта идея дала христианству невероятную устойчивость перед лицом гонений. И именно она до сих пор остаётся камнем преткновения: принять или отвергнуть её — значит принять или отвергнуть всё здание христианской веры."},
  {"title":"Любовь-агапе — определение, которое не устарело","example":"В греческом языке есть четыре слова для разных видов любви. Эрос — романтическая страсть. Сторге — семейная привязанность. Филия — дружеская любовь. Агапе — безусловная, жертвенная любовь, не зависящая от того, заслужил ли её объект. Именно агапе — центральное слово Нового Завета. Апостол Павел в 13-й главе Первого послания к Коринфянам даёт определение, которое за 2000 лет не устарело ни на слово: «Любовь долготерпит, милосердствует, любовь не завидует, любовь не превозносится, не гордится, не бесчинствует, не ищет своего, не раздражается, не мыслит зла, не радуется неправде, а сорадуется истине; всё покрывает, всему верит, всего надеется, всё переносит». Это не эмоция — это решение. Психолог Эрих Фромм в книге «Искусство любить» разбирал агапе как практику, а не чувство. Современная психология отношений — теория привязанности, концепция безусловного принятия — строится на тех же принципах, что описал Павел."},
  {"title":"Экклезиаст — самая честная книга о смысле жизни","example":"«Суета сует, всё суета» — так начинается Екклезиаст. Автор называет себя царём Иерусалимским, человеком с неограниченными ресурсами. Он перепробовал всё: накопил мудрость больше всех предшественников — и обнаружил, что это тоже суета. Построил дома, разбил сады, завёл слуг и скот, собрал серебро и золото. Суета. Предался веселью и удовольствиям. Суета. Трудился без остановки. Суета. Это не пессимизм и не нигилизм — это честность. Автор говорит: посмотрите на жизнь без иллюзий. Ни богатство, ни мудрость, ни удовольствие сами по себе не дают смысла. Но в конце книга приходит к выводу: «Бойся Бога и соблюдай заповеди Его, потому что в этом всё для человека». Экзистенциальные философы — Камю, Сартр, Кьеркегор — задавали те же вопросы три тысячи лет спустя. Экклезиаст опередил их всех."},
  {"title":"Псалмы — язык человеческой души на все времена","example":"В Псалтири 150 стихотворений, написанных за несколько столетий разными авторами. Они охватывают весь диапазон человеческих состояний без цензуры: «Боже мой, Боже мой! для чего Ты оставил меня?» — это крик отчаяния, который Иисус повторил на кресте. «Господь — пастырь мой; я ни в чём не буду нуждаться» — это покой полного доверия. Есть псалмы гнева, где автор молит Бога уничтожить врагов. Есть псалмы ликования, где каждое дыхание превращается в хвалу. Именно поэтому Псалмы цитируют умирающие и рожающие, солдаты в окопах и монахи в тишине, люди в депрессии и люди на вершине счастья. За три тысячи лет человеческий диапазон переживаний не изменился. И Псалмы дают язык для состояний, для которых у нас иначе нет слов. Психотерапевты отмечают: пациентам иногда легче выразить страдание через псалом, чем собственными словами."}
]

quran_thoughts = [
  {"title":"Таухид — единобожие как основа всего мировоззрения","example":"«Нет Бога кроме Аллаха» — это не просто религиозная формула. Это фундаментальное утверждение о природе реальности. В мире, где каждое явление природы — гром, дождь, плодородие — имело своего бога, ислам предложил революционную идею: за всем этим стоит одна причина, один разум, один закон. Из таухида вытекает несколько важнейших следствий. Первое: все люди равны перед одним Богом — нет расы, племени или народа, которому Бог покровительствует больше других. Второе: природа единообразна и познаваема, потому что создана одним творцом по единым законам. Именно это убеждение дало импульс арабской науке золотого века. Ибн аль-Хайсам разработал основы оптики. Аль-Хорезми создал алгебру. Авиценна написал медицинский канон, который использовали в европейских университетах 600 лет. Всё это было религиозным проектом: познавать природу значило познавать творение Бога."},
  {"title":"Пять столпов — архитектура осмысленной жизни","example":"Ислам структурирует жизнь через пять обязательных практик. Шахада — исповедание веры: нет Бога кроме Аллаха, Мухаммад — его посланник. Это не просто декларация, а постоянное напоминание об основе. Салят — пятикратная молитва в день: на рассвете, в полдень, во второй половине дня, на закате и ночью. Каждые три-четыре часа человек останавливается, оставляет всё и обращается к Богу. Это встроенная практика осознанности задолго до того, как медитация стала модной. Закят — обязательный взнос 2,5% от сбережений в пользу бедных. Не благотворительность по желанию — религиозный долг. Саум — пост в месяц Рамадан: от рассвета до заката без еды и питья. Это не просто воздержание — это ежегодная перезагрузка, опыт солидарности с голодающими. Хадж — паломничество в Мекку хотя бы раз в жизни для тех, кто способен. На хаджж собираются миллионы людей всех рас и стран — в одинаковой белой одежде, без различий статуса. Пять столпов создают ритм, в котором духовное не отделено от повседневного."},
  {"title":"Милосердие — первое и главное качество Бога","example":"Каждая из 114 сур Корана начинается со слов «Бисмиллах ир-рахман ир-рахим» — «Во имя Аллаха, Милостивого, Милосердного». Два слова — Ар-Рахман и Ар-Рахим — оба происходят от арабского корня «рахма», означающего милосердие, нежность, материнскую любовь. Ар-Рахман — безграничное милосердие ко всем творениям без исключения. Ар-Рахим — особое милосердие к верующим. Это намеренная расстановка акцентов: прежде чем говорить о законе, наказании или справедливости, Коран ставит милосердие на первое место. В исламской теологии 99 имён Бога — и среди них Справедливый, Мощный, Мудрый. Но именно Милостивый и Милосердный — те имена, которые произносятся перед каждым действием, каждым текстом, каждой молитвой. Это не случайно: составители Корана хотели, чтобы каждый мусульманин сотни раз в день напоминал себе — в основе веры лежит милосердие, а не страх."},
  {"title":"Знание — первая заповедь ислама","example":"Первое слово, ниспосланное пророку Мухаммаду через архангела Джибриля, было «Икра» — читай, учись, познавай. Пророк Мухаммад был неграмотным — и именно ему была дана заповедь читать. Это символично: знание — не привилегия образованных, а обязанность каждого. Коран многократно возвышает учёных: «Разве равны те, которые знают, и те, которые не знают?» Пророк Мухаммад говорил: «Ищи знание от колыбели до могилы» и «Ищи знание, даже если для этого надо ехать в Китай». В результате первые века ислама стали эпохой невероятного интеллектуального расцвета. Арабские учёные переводили греческих философов, индийских математиков, персидских астрономов — и развивали их идеи дальше. Слова «алгебра», «алгоритм», «алхимия», «алкоголь» — арабского происхождения. Цифры, которые мы используем сегодня — «арабские». Когда Европа переживала Тёмные века, исламский мир сохранял и приумножал знания человечества."},
  {"title":"Судный день — ответственность как основа этики","example":"Коран подробно описывает Судный день: все люди без исключения предстанут перед Аллахом, и каждое их деяние будет взвешено на весах справедливости. «Кто сделал добро весом в пылинку — увидит его. Кто сделал зло весом в пылинку — увидит его». Зачем эта концепция? Потому что она решает фундаментальную проблему морали: что удерживает человека от плохих поступков, когда его никто не видит? Страх наказания здесь и сейчас — ненадёжный якорь: можно не попасться. Общественное осуждение — тоже ненадёжно: можно скрыть. Убеждение, что каждый поступок записан и будет рассмотрен — это другой уровень ответственности, работающий даже в полной темноте. Именно поэтому концепция посмертного суда и воздаяния существует в той или иной форме практически во всех мировых религиях — она закрывает принципиальную брешь в человеческой этике."},
  {"title":"Закят — обязательная социальная справедливость","example":"Закят — один из пяти столпов ислама. Каждый мусульманин, чьё состояние превышает определённый порог, обязан ежегодно отдавать 2,5% накопленных сбережений в пользу нуждающихся. Важно: это не благотворительность по настроению, не добровольный жест — это религиозный долг, такой же обязательный, как молитва. Коран называет восемь категорий получателей закята: бедные, нищие, должники, путники, оказавшиеся в нужде, те, кто занимается его сбором и распределением. Это продуманная система перераспределения, разработанная в VII веке — за тысячу лет до современных концепций прогрессивного налогообложения. В периоды расцвета исламской цивилизации — при Омейядах и Аббасидах — система закята реально функционировала и снижала социальное неравенство. Современные исламские экономисты активно разрабатывают модели закята применительно к финансовым инструментам XXI века."},
  {"title":"Сабр — терпение как высшая форма силы","example":"Слово «сабр» в арабском языке не имеет точного аналога в русском. Это одновременно терпение, стойкость, выносливость и внутренняя сила перед лицом испытания. Сабр встречается в Коране более 90 раз — больше, чем большинство других добродетелей. «Аллах с терпеливыми» — одна из наиболее часто цитируемых фраз. Это меняет саму рамку отношения к трудностям. Вместо вопроса «почему это случилось со мной» — вопрос «как я пройду через это достойно». Вместо поиска виноватых — поиск смысла и возможности роста. Современная психология resilience — науки об устойчивости — пришла к схожим выводам: люди, воспринимающие трудности не как катастрофу, а как испытание с возможным смыслом, восстанавливаются быстрее, сохраняют психическое здоровье и достигают большего. Концепция сабра описывает этот механизм с точностью, недостижимой для многих современных психологических теорий."},
  {"title":"Природа как книга знамений","example":"В Коране слово «аят» имеет двойное значение: стих священного текста и знак, знамение в природе. Это не случайное совпадение — это мировоззренческая установка. Коран многократно призывает смотреть на природу как на источник знания о Боге: «Разве они не смотрят на верблюдов — как они созданы? На небо — как оно воздвигнуто? На горы — как они водружены? На землю — как она распростёрта?» Для мусульманского учёного изучение природы было актом богопознания. Именно поэтому средневековые исламские учёные занимались астрономией, математикой, медициной, химией — не вопреки вере, а благодаря ей. Природа в исламе — не объект поклонения и не случайный хаос, а книга, написанная Богом для тех, кто умеет читать. Современные мусульманские богословы используют эту традицию для обоснования экологической ответственности: раз природа — знамение Бога, её уничтожение есть кощунство."},
  {"title":"Умма — братство поверх всех границ","example":"Умма — мусульманская община — одна из самых революционных концепций в истории человечества. В доисламской Аравии идентичность определялась племенем: ты был сыном своего клана, и это определяло всё — кому ты помогаешь, кому мстишь, кому доверяешь. Ислам предложил идентичность другого порядка: ты мусульманин, и это важнее любой крови. Пророк Мухаммад в своей последней проповеди сказал: «Нет превосходства у араба над неарабом, и у неараба над арабом, и у белого над чёрным, и у чёрного над белым — кроме как в богобоязненности». В VII веке это была невероятно радикальная декларация равенства. Практически умма позволила создать первую в истории наднациональную торговую и политическую сеть — от Испании до Индонезии, объединённую общим языком молитвы, общим правом и общими ценностями. Ни одна империя до этого не достигала такого масштаба добровольной интеграции."},
  {"title":"Человек — наместник Бога на земле","example":"В Коране есть удивительный эпизод: когда Бог объявляет ангелам, что создаст на земле наместника — халифа — ангелы возражают: «Разве Ты поставишь на ней того, кто будет творить нечестие и проливать кровь?» Бог отвечает: «Я знаю то, чего вы не знаете». Статус халифа — это не лесть и не повод для гордости. Это ответственность. Наместник не владелец, а управляющий. Земля дана человеку в попечение, а не в собственность. Из этого следует экологическая этика, которая сегодня становится всё более актуальной: уничтожать природные ресурсы — значит нарушать свои обязанности перед Богом. Современные исламские экологические движения строят свою аргументацию именно на концепции халифата: мы не хозяева Земли, мы её временные управляющие, и нам держать ответ за то, в каком состоянии мы её передадим следующим поколениям."}
]

